    "daunting":     { example: "Moving to a new country can be daunting, but also incredibly rewarding.", exampleJa: "新しい国に移住することは怖気づかせるかもしれませんが、非常にやりがいもあります。" },
    "genuinely":    { example: "She was genuinely surprised by the warm reception she received.", exampleJa: "彼女は受けた温かい歓迎に心から驚きました。" },
    "profoundly":   { example: "The experience profoundly changed the way he viewed the world.", exampleJa: "その経験は彼が世界を見る方法を深く変えました。" },
    "consequently": { example: "The storm damaged the power grid; consequently, the city was left in darkness.", exampleJa: "嵐が電力網を損傷し、その結果市は暗闇に包まれました。" },
    "presumably":   { example: "The meeting was cancelled, presumably due to the bad weather.", exampleJa: "会議はおそらく悪天候のためにキャンセルされました。" },
