    "disdain":      { example: "She disdained shortcuts and insisted on doing the work thoroughly.", exampleJa: "彼女は近道を軽蔑し、仕事を徹底的に行うことにこだわりました。" },
    "dissuade":     { example: "His mentor tried to dissuade him from abandoning the research midway.", exampleJa: "彼の師は彼が研究を途中で放棄するのを思いとどまらせようとしました。" },
    "misappropriate": { example: "The treasurer was convicted of misappropriating funds donated to the charity.", exampleJa: "会計担当者は慈善団体に寄付された資金を横領したとして有罪判決を受けました。" },
    "underwrite":   { example: "The bank agreed to underwrite the entire cost of the infrastructure project.", exampleJa: "銀行はインフラプロジェクトの全費用を引き受けることに同意しました。" },
    "underwhelm":   { example: "Critics were underwhelmed by the sequel, which offered nothing new.", exampleJa: "批評家たちは何も新しいものを提供しない続編に感銘を受けませんでした。" },
