    "complacence":  { example: "Complacence after early success proved fatal to the project's long-term goals.", exampleJa: "初期の成功後の油断がプロジェクトの長期目標に致命的であることが証明されました。" },
    "exuberance":   { example: "The crowd's exuberance was palpable as the team scored the winning goal.", exampleJa: "チームが決勝点を入れると、群衆の溢れる熱気が感じ取れました。" },
    "nonchalance":  { example: "He accepted the award with an air of nonchalance that surprised the audience.", exampleJa: "彼は聴衆を驚かせる無頓着な様子で賞を受け取りました。" },
    "composure":    { example: "Despite the chaos around her, she maintained her composure throughout.", exampleJa: "周囲の混乱にもかかわらず、彼女はずっと平静さを保ちました。" },
    "conjecture":   { example: "The cause of the ancient civilisation's collapse remains a matter of conjecture.", exampleJa: "その古代文明の崩壊の原因は推測の域を出ていません。" },
    "lineage":      { example: "The royal family traces its lineage back over five hundred years.", exampleJa: "王室はその家系を500年以上さかのぼって辿ることができます。" },

    // ── level-3 adjectives / adverbs ─────────────────
    "preeminent":   { example: "She is widely regarded as the preeminent authority on medieval linguistics.", exampleJa: "彼女は中世言語学の最高権威として広く認められています。" },
    "unequivocal":  { example: "The committee issued an unequivocal statement condemning the violence.", exampleJa: "委員会は暴力を非難する明確な声明を発表しました。" },
    "unmitigated":  { example: "The launch was an unmitigated disaster — nothing went as planned.", exampleJa: "そのローンチは完全な惨事でした — 何ひとつ計画通りにいきませんでした。" },
    "untenable":    { example: "His position became untenable once the contradictions in his story emerged.", exampleJa: "彼の話の矛盾が明らかになると、彼の立場は維持できなくなりました。" },
    "unwieldy":     { example: "The unwieldy bureaucracy made even simple reforms difficult to implement.", exampleJa: "扱いにくい官僚制度は単純な改革さえも実施することを困難にしました。" },
    "unscrupulous": { example: "Unscrupulous vendors exploit vulnerable consumers with false advertising.", exampleJa: "悪徳業者は虚偽広告で脆弱な消費者を搾取します。" },
    "overzealous":  { example: "Overzealous enforcement of minor rules created resentment among employees.", exampleJa: "軽微なルールの過剰な施行が従業員の間に不満を生み出しました。" },
    "overweening":  { example: "His overweening confidence blinded him to the genuine risks of the venture.", exampleJa: "彼の傲慢な自信は事業の本当のリスクを見えなくしました。" },
    "subliminal":   { example: "Advertisers sometimes embed subliminal cues to influence purchasing behaviour.", exampleJa: "広告主はときに購買行動に影響を与えるために潜在意識へのサインを埋め込みます。" },
    "superfluous":  { example: "The editor removed all superfluous details to sharpen the argument.", exampleJa: "編集者は議論を鋭くするためにすべての余計な詳細を削除しました。" },
    "supercilious": { example: "His supercilious manner alienated colleagues who might have been his allies.", exampleJa: "彼の傲慢な態度は味方になったかもしれない同僚を遠ざけました。" },
    "intermittent": { example: "The satellite link suffered from intermittent outages throughout the conference.", exampleJa: "衛星回線は会議中ずっと断続的な障害に悩まされました。" },
    "interminable": { example: "What was supposed to be a brief meeting turned into an interminable discussion.", exampleJa: "短いはずだった会議が果てしない議論になってしまいました。" },
    "transient":    { example: "Fame can be transient; what endures is the quality of one's character.", exampleJa: "名声は一時的なものかもしれませんが、持続するのは人格の質です。" },
    "transcendent": { example: "The mountain landscape inspired a sense of the transcendent in all who saw it.", exampleJa: "山の景色はそれを見たすべての人に超越的な感覚を呼び起こしました。" },
    "anticlimactic": { example: "After years of anticipation, the summit's outcome was deeply anticlimactic.", exampleJa: "何年もの期待の後、サミットの結果は非常にがっかりするものでした。" },
    "autoimmune":   { example: "Autoimmune diseases occur when the body mistakenly attacks its own healthy tissue.", exampleJa: "自己免疫疾患は体が誤って自分の健康な組織を攻撃するときに起こります。" },
    "autochthonous": { example: "The autochthonous population has lived in this region for thousands of years.", exampleJa: "その土着の集団はこの地域に何千年もの間暮らしてきました。" },
    "collateral":   { example: "Civilian casualties were described as collateral damage in the official report.", exampleJa: "民間人の犠牲者は公式報告書で付随的損害として説明されました。" },
