    "cryptocurrency": { example: "Cryptocurrency transactions are verified through decentralised blockchain networks.", exampleJa: "仮想通貨の取引は分散型ブロックチェーンネットワークを通じて検証されます。" },
    "cryptogram":   { example: "The detective decoded the cryptogram hidden inside the suspect's notebook.", exampleJa: "探偵は容疑者のノートに隠された暗号文を解読しました。" },
    "cryptographer": { example: "The cryptographer developed new algorithms to protect sensitive government communications.", exampleJa: "暗号学者は機密の政府通信を保護するための新しいアルゴリズムを開発しました。" },
    "cryptography": { example: "Modern internet security relies heavily on advanced cryptography to protect data.", exampleJa: "現代のインターネットセキュリティはデータを保護するために高度な暗号技術に大きく依存しています。" },
    "cryptology":   { example: "Cryptology combines cryptography and cryptanalysis to study secret communication systems.", exampleJa: "暗号学は暗号技術と暗号解析を組み合わせて秘密通信システムを研究します。" },
