    "manslaughter": { example: "He was convicted of manslaughter after the accidental death was investigated.", exampleJa: "事故死が調査された後、彼は過失致死で有罪判決を受けました。" },
    "accomplice":   { example: "The thief and his accomplice were both arrested at the scene of the crime.", exampleJa: "泥棒とその共犯者は両方とも犯行現場で逮捕されました。" },
    "separation of powers": { example: "The separation of powers prevents any single branch of government from becoming too powerful.", exampleJa: "権力分立は政府のいずれかの部門が強大になりすぎるのを防ぎます。" },
    "reinforcement": { example: "Positive reinforcement is more effective than punishment in shaping behavior.", exampleJa: "正の強化は行動を形成する上で罰よりも効果的です。" },
