    "refute":       { example: "Scientists were quick to refute the claims made in the misleading article.", exampleJa: "科学者たちは誤解を招く記事でなされた主張を素早く反証しました。" },
    "reinstate":    { example: "The employee was reinstated after an investigation proved the dismissal was wrongful.", exampleJa: "解雇が不当だったことが調査で証明された後、従業員は復職しました。" },
    "reiterate":    { example: "The manager reiterated the safety procedures to ensure everyone understood them.", exampleJa: "マネージャーは全員が理解できるよう安全手順を繰り返し説明しました。" },
