    "rehabilitate": { example: "The program aims to rehabilitate offenders and reduce the risk of reoffending.", exampleJa: "そのプログラムは犯罪者を更生させ再犯リスクを減らすことを目指しています。" },
    "rejuvenate":   { example: "A week of rest and good food completely rejuvenated her after the exhausting project.", exampleJa: "一週間の休息と良い食事が消耗したプロジェクトの後に彼女を完全に若返らせました。" },
    "reprimand":    { example: "The supervisor reprimanded the employee for repeatedly arriving late to work.", exampleJa: "上司は仕事に繰り返し遅刻した従業員を叱責しました。" },
