    "preempt":      { example: "The company launched its product early to preempt a rival's competing release.", exampleJa: "会社はライバルの競合製品の発売を先取りするために早期に製品を発売しました。" },
    "prefabricate": { example: "Prefabricated housing panels are assembled on-site to reduce construction time.", exampleJa: "プレハブ式住宅パネルは建設時間を短縮するために現場で組み立てられます。" },
    "prelude":      { example: "The warm-up speech served as a prelude to the main keynote address.", exampleJa: "ウォームアップスピーチは基調講演への前置きとして機能しました。" },
