    "predominate":  { example: "Team sports predominate in the school curriculum, with few individual activities offered.", exampleJa: "学校のカリキュラムではチームスポーツが主流で、個人競技はほとんど提供されていません。" },
    "precursor":    { example: "Rising unemployment is often a precursor to social unrest.", exampleJa: "失業率の上昇はしばしば社会不安の前触れです。" },
    "predispose":   { example: "Certain genetic factors can predispose individuals to developing heart disease.", exampleJa: "特定の遺伝的要因は心臓病を発症する素因を個人に与えることがあります。" },
    "predetermined": { example: "Critics argued that the outcome of the trial appeared to be predetermined.", exampleJa: "批評家たちは裁判の結果があらかじめ決まっていたように見えると主張しました。" },
    "presuppose":   { example: "The theory presupposes that all participants act in a perfectly rational manner.", exampleJa: "その理論はすべての参加者が完全に合理的な方法で行動することを前提としています。" },
    "prejudicial":  { example: "The judge ruled that the leaked evidence was prejudicial to a fair trial.", exampleJa: "裁判官は漏洩した証拠が公正な裁判に不利益であると判決しました。" },
