    "typography":   { example: "Good typography makes text easier to read and enhances the overall design.", exampleJa: "良いタイポグラフィはテキストを読みやすくし全体的なデザインを向上させます。" },
    "oceanography": { example: "Oceanography studies ocean currents, marine life, and seabed geology.", exampleJa: "海洋学は海流、海洋生物、海底地質学を研究します。" },
