    "rigorous":     { example: "The rigorous training program prepared the soldiers for the most demanding conditions.", exampleJa: "厳格な訓練プログラムは兵士たちを最も過酷な条件に備えさせました。" },
    "tentative":    { example: "We made a tentative plan to meet next week but haven't confirmed the details.", exampleJa: "来週会う暫定的な計画を立てましたが、詳細はまだ確認していません。" },
    "stabilize":    { example: "The central bank intervened to stabilize the currency after a sharp decline.", exampleJa: "急落後に通貨を安定させるために中央銀行が介入しました。" },
    "stigmatize":   { example: "Mental illness should not be stigmatized, as it affects millions of people worldwide.", exampleJa: "精神疾患は世界中で何百万もの人々に影響するため、スティグマ化されるべきではありません。" },
    "ostracize":    { example: "She was ostracized by her classmates after refusing to join their group.", exampleJa: "グループへの参加を拒否した後、彼女はクラスメートから村八分にされました。" },
    "transformation": { example: "The transformation of the run-down warehouse into a modern art gallery was remarkable.", exampleJa: "老朽化した倉庫を現代的な美術館に変える変容は目覚ましいものでした。" },
