    "realign":          { example: "The company realigned its strategy after poor sales.", exampleJa: "会社は売上不振を受けて戦略を見直しました。" },
    "recapture":        { example: "Troops moved in to recapture the lost territory.", exampleJa: "部隊は失った領土を奪還するために進軍しました。" },
    "reconfigure":      { example: "The IT team reconfigured the network after the breach.", exampleJa: "ITチームはセキュリティ侵害の後にネットワークを再設定しました。" },
    "recount":          { example: "Officials requested a recount after the close election.", exampleJa: "接戦の選挙の後、当局は票の再集計を求めました。" },
    "recoup":           { example: "The studio hoped to recoup its losses with the sequel.", exampleJa: "スタジオは続編で損失を取り戻すことを期待していました。" },
    "reevaluate":       { example: "We need to reevaluate our approach after the setback.", exampleJa: "失敗の後、私たちはアプローチを再評価する必要があります。" },
    "reinvest":         { example: "They chose to reinvest the profits back into the business.", exampleJa: "彼らは利益を事業に再投資することを選びました。" },
    "reinvigorate":     { example: "The new leadership reinvigorated the struggling organization.", exampleJa: "新しいリーダーシップが苦境に立つ組織に活力をもたらしました。" },
    "rejoice":          { example: "The whole town rejoiced when the team won the championship.", exampleJa: "チームが優勝したとき、町全体が歓喜に湧きました。" },
    "release":          { example: "The studio released the film on streaming platforms.", exampleJa: "スタジオはその映画をストリーミングプラットフォームで公開しました。" },
    "relent":           { example: "After hours of negotiation, the landlord finally relented.", exampleJa: "何時間もの交渉の末、家主はついに折れました。" },
    "relieve":          { example: "Medication helped relieve her chronic back pain.", exampleJa: "薬が彼女の慢性的な腰痛を和らげるのに役立ちました。" },
    "remain":           { example: "Several issues remain unresolved after the summit.", exampleJa: "首脳会談の後もいくつかの問題が未解決のままです。" },
    "remediate":        { example: "Engineers were hired to remediate the contaminated soil.", exampleJa: "汚染された土壌を修復するために技術者が雇われました。" },
    "remove":           { example: "Please remove your shoes before entering.", exampleJa: "中に入る前に靴を脱いでください。" },
