    "credible":      { example: "The report's findings were credible because they were supported by data from multiple independent sources.", exampleJa: "報告書の調査結果は複数の独立した情報源のデータによって支持されていたため、信頼性があった。" },
    "culpable":      { example: "The court found the company culpable for the environmental damage caused by its waste disposal practices.", exampleJa: "裁判所は廃棄物処理慣行によって引き起こされた環境への損害について会社に責任があるとした。" },

    // ── missing-examples-batch-012 ───────────────────────────────────────────
    "cunning":       { example: "The fox in the fable is admired for its cunning, always outsmarting the larger animals.", exampleJa: "寓話の狐は常に大きな動物を出し抜く、その狡猾さで称賛されている。" },
    "curb":          { example: "The city introduced new measures to curb the rise in road accidents near schools.", exampleJa: "市は学校近くの交通事故増加を抑制するための新しい対策を導入した。" },
    "cursory":       { example: "A cursory reading of the contract missed a clause that proved costly later.", exampleJa: "契約書のざっと読んでいたため、後に高くつく条項を見逃してしまった。" },
    "cynical":       { example: "Years of failed promises had made the electorate deeply cynical about political pledges.", exampleJa: "何年にもわたる失われた約束が有権者を政治的公約に対して深く懐疑的にさせた。" },
    "daunting":      { example: "The scale of the task was daunting, but the team broke it into manageable steps.", exampleJa: "タスクの規模は手ごわいものだったが、チームはそれを管理可能なステップに分解した。" },
    "debacle":       { example: "The product launch was a debacle, with the website crashing and orders going missing.", exampleJa: "ウェブサイトがクラッシュして注文が消えてしまうという、その製品発売は大失敗に終わった。" },
    "decry":         { example: "Critics decried the decision to close the local library, calling it an act of cultural vandalism.", exampleJa: "批評家たちは地元図書館の閉鎖を文化的破壊行為と呼び、その決定を非難した。" },
    "defer":         { example: "She decided to defer her university place by a year to travel and gain work experience.", exampleJa: "彼女は旅行と職業経験を積むために大学の入学を1年間延期することを決めた。" },
    "defiant":       { example: "The defiant statement from the accused surprised even experienced observers at the hearing.", exampleJa: "被告からの反抗的な声明は聴聞会の経験豊富な観察者たちさえも驚かせた。" },
    "deliberate":    { example: "The slow, deliberate pace of the negotiation was clearly a tactical choice.", exampleJa: "交渉のゆっくりとした慎重なペースは明らかに戦術的な選択だった。" },
    "deluge":        { example: "After the article was published, the newspaper was deluged with letters from readers.", exampleJa: "記事が掲載された後、新聞社は読者からの手紙の洪水に見舞われた。" },
