    "denounce":      { example: "Human rights groups denounced the new law as an attack on freedom of expression.", exampleJa: "人権団体は新しい法律を表現の自由への攻撃として非難した。" },
    "deplete":       { example: "Intensive farming has gradually depleted the nutrient content of the surrounding soil.", exampleJa: "集約農業は周囲の土壌の栄養素を徐々に枯渇させてきた。" },
    "deprecate":     { example: "The software team deprecated the old API endpoint, giving users six months to migrate.", exampleJa: "ソフトウェアチームは古いAPIエンドポイントを非推奨とし、ユーザーに6ヶ月の移行期間を与えた。" },
    "derive":        { example: "She derived considerable satisfaction from mentoring younger members of the team.", exampleJa: "彼女はチームの若いメンバーを指導することからかなりの満足感を得た。" },
    "deter":         { example: "The harsh sentencing was intended to deter others from committing similar offences.", exampleJa: "厳しい量刑は他の人が同様の犯罪を犯すことを抑止することを意図していた。" },
    "deviate":       { example: "The project had deviated significantly from the original scope without anyone noticing.", exampleJa: "誰にも気づかれることなく、プロジェクトは当初のスコープから大幅に逸脱していた。" },
    "dilemma":       { example: "The nurse faced a dilemma between following protocol and doing what she judged was best for the patient.", exampleJa: "看護師はプロトコルに従うことと患者にとって最善と判断したことをすることの間のジレンマに直面した。" },
    "diligent":      { example: "Her diligent approach to revision meant she entered the exam with complete confidence.", exampleJa: "彼女の勤勉な復習へのアプローチは、完全な自信を持って試験に臨むことができた。" },
    "diminish":      { example: "His confidence had diminished significantly after the public failure of his first business.", exampleJa: "最初のビジネスの公の失敗の後、彼の自信はかなり低下していた。" },
    "discern":       { example: "It takes experience to discern which client concerns are genuine and which are negotiating tactics.", exampleJa: "どのクライアントの懸念が本物でどれが交渉戦術かを見極めるには経験が必要だ。" },
    "discredit":     { example: "The defence team worked to discredit the key witness by highlighting inconsistencies in his testimony.", exampleJa: "弁護チームは証言の矛盾点を指摘することで主要証人の信用を失墜させようとした。" },
    "dismantle":     { example: "The government announced plans to dismantle the agency and distribute its functions to other departments.", exampleJa: "政府は機関を解体し、その機能を他の部署に分散させる計画を発表した。" },
    "dispel":        { example: "The press statement was designed to dispel rumours that had been circulating in the industry.", exampleJa: "プレス声明は業界で流れていた噂を払拭するように設計されていた。" },

    // ── missing-examples-batch-013 ───────────────────────────────────────────
    "dissent":       { example: "A single voice of dissent in the committee raised concerns that others had been afraid to voice.", exampleJa: "委員会の一人の反対意見が他の人が言い出せなかった懸念を呼び起こした。" },
    "distort":       { example: "The report was accused of distorting the facts to support a predetermined conclusion.", exampleJa: "報告書は事前に決まった結論を支持するために事実を歪曲していると非難された。" },
    "diverge":       { example: "The two studies used similar methods but diverged sharply in their conclusions.", exampleJa: "2つの研究は同様の方法を使用したが、結論において大きく分かれた。" },
