    "innovative":    { example: "The award was given to the most innovative approach to reducing plastic waste submitted that year.", exampleJa: "その賞はその年に提出されたプラスチック廃棄物削減への最も革新的なアプローチに授与された。" },
    "insightful":    { example: "Her insightful commentary on the data gave the board a much clearer sense of the trends.", exampleJa: "彼女のデータに対する洞察力のある解説は取締役会にトレンドのより明確な感覚を与えた。" },
    "integrity":     { example: "She was respected throughout the industry for her integrity in dealings with clients and suppliers alike.", exampleJa: "彼女はクライアントとサプライヤーの両方との取引における誠実さで業界全体で尊重されていた。" },
    "intricate":     { example: "The surgeon described the procedure as highly intricate, requiring six hours in the operating theatre.", exampleJa: "外科医はその処置を非常に複雑なもので、手術室での6時間を要すると説明した。" },
    "intuitive":     { example: "The interface was so intuitive that new users could navigate it without reading the manual.", exampleJa: "インターフェースはとても直感的で、新しいユーザーはマニュアルを読まずに操作できた。" },
    "irony":         { example: "The irony was that the campaign designed to build trust had the opposite effect.", exampleJa: "皮肉なことに、信頼を築くために設計されたキャンペーンが逆効果をもたらした。" },
    "jeopardise":    { example: "Publishing the story early would jeopardise the entire investigation, warned the detective.", exampleJa: "記事を早期に公開することで捜査全体が危険にさらされると刑事は警告した。" },
    "jubilant":      { example: "The jubilant crowd spilled onto the streets after the final whistle confirmed their team's victory.", exampleJa: "最終ホイッスルがチームの勝利を確認した後、歓喜した群衆が通りにあふれ出た。" },
    "keen":          { example: "She was keen to make a good impression in the first week at her new job.", exampleJa: "彼女は新しい仕事の最初の週に良い印象を与えることを熱望していた。" },

